import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"基础武学-指法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-指法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-指法.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-指法.md"};function _(p,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"基础武学-指法",tabindex:"-1"},[s("基础武学-指法 "),e("a",{class:"header-anchor",href:"#基础武学-指法","aria-label":'Permalink to "基础武学-指法"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="基础武学-指法-1" tabindex="-1">基础武学-指法 <a class="header-anchor" href="#基础武学-指法-1" aria-label="Permalink to &quot;基础武学-指法&quot;">​</a></h1><p>基础武学-指法<br> 江湖中最最基础的武功招法，在结合不同的基本功和兵器招式之后，大囧朝廷通过总结推演出新，创新性的为百姓和天下所有武学新人创造了这些更接近于实战的基础武功，并划分江南漠北地区二十八县推广推陈，力求普及，为未来扫平江湖提前埋下另一道伏笔。</p><p>本系列下所有能力皆需要内力能量池才可购买。</p><p>基础指法 D+1250<br> 练法是，将一块厚约寸余的青石板搁在板凳上，高及人的腹部。练功者将指甲剪净，距石板半尺成马步，两手屈于胸前，自然下垂，以两手手指在石板上缓慢来回抚摩。用意不用力自然和缓。半小时以后，可用十指在石板各处点打200次。击打时要用腕力，要有弹性，点打分明，点后即起。用力不可太猛，然而意念须击石而穿。练久后，指尖会慢慢磨平，十指发烫，偶尔还会发硬。直到五指在木板、石板、青砖上能击打出凹印时，指力已十分锋利，就大功告成了。<br> 完成训练之后，你的肉搏天生武器获得3L武器伤害。<br> 指力已成的武者不在光凭一时血勇而战，此时你的双手经脉已通气走其中，激战之时运使内力流转，指力随内力散射，凝而不散力贯其中，这就是指法武功基本功已成的气势。<br> 花费标准动作进行天生武器攻击，消耗1内力，你的可攻击范围额外增加3米，并且具有5威猛。</p><p>这是一个攻击技。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
